/* Pseudocode (Python-style) demonstrating an idempotency claim */
# Attempt to claim idempotency key (atomic single-row insert)
try:
    db.insert('idempotency', { 'account_id': acct, 'key': key, 'status': 'inflight' })
    # success -> process asynchronously
    enqueue_work(acct, key, payload)
    return { 'status': 202, 'message': 'Accepted - processing' }
except UniqueConstraintViolation:
    row = db.select('idempotency', where={ 'account_id': acct, 'key': key })
    if row.status == 'completed':
        return row.stored_response
    elif row.status == 'inflight':
        return { 'status': 202, 'message': 'Accepted - retry soon' }

# Worker: process and store result
result = call_payment_gateway(payload)
db.update('idempotency', where={ 'account_id': acct, 'key': key }, set={ 'status': 'completed', 'response': result })
cache.set(cache_key(acct, key), result, ttl=60*60*24)  # keep for 24h
